INSERT INTO seasons VALUES(1,'Phantom Blood',1,2012,'In late 19th-century England, the young Jonathan Joestar meets his new adopted brother Dio Brando, who only wants to usurp Jonathan as heir to the Joestar family. When Dio''s attempts are thwarted, he uses an ancient Stone Mask that transforms him into a vampire.',NULL,'2026-03-16 12:14:24','2026-03-16 12:14:24','https://www.youtube.com/watch?v=m_vux8N_bdU');
INSERT INTO seasons VALUES(2,'Battle Tendency',2,2012,'In 1938 New York City, Jonathan''s grandson Joseph Joestar must master the power of Hamon to defeat the Pillar Men, ancient humanoid beings who created the Stone Mask.',NULL,'2026-03-16 12:14:24','2026-03-16 12:14:24','https://www.youtube.com/watch?v=m_vux8N_bdU');
INSERT INTO seasons VALUES(3,'Stardust Crusaders',3,2014,'Jotaro Kujo travels to Egypt to defeat the resurrected Dio and save his mother.',NULL,'2026-03-16 12:14:24','2026-03-16 12:14:24','https://www.youtube.com/watch?v=nS4ToRiZ2mQ');
INSERT INTO seasons VALUES(4,'Diamond Is Unbreakable',4,2016,'Josuke Higashikata protects the town of Morioh from a serial killer with a Stand.',NULL,'2026-03-16 12:14:24','2026-03-16 12:14:24','https://www.youtube.com/watch?v=Be6Go_PhX9E');
INSERT INTO seasons VALUES(5,'Golden Wind',5,2018,'Giorno Giovanna dreams of becoming a Gang-Star to clean up the Italian mafia.',NULL,'2026-03-16 12:14:24','2026-03-16 12:14:24','https://www.youtube.com/watch?v=M9G9ZOCNbNo');
INSERT INTO seasons VALUES(6,'Stone Ocean',6,2021,'Jolyne Cujoh is framed for a crime and must escape Green Dolphin Street Prison.',NULL,'2026-03-16 12:14:24','2026-03-16 12:14:24','https://www.youtube.com/watch?v=eeTGGVIsGIs');
